const r=r=>{const t=/^#?([a-fA-F0-9]{6})$/.exec(r),a=t?t[1]:"#7C3AED".replace("#",""),n=parseInt(a,16);return{r:n>>16&255,g:n>>8&255,b:255&n}},t=(t,a=.3)=>{const{r:n,g:o,b:e}=r(t),s=r=>Math.round(r+(255-r)*a);return`#${[s(n),s(o),s(e)].map((r=>r.toString(16).padStart(2,"0"))).join("")}`},a=(t,a=.2)=>{const{r:n,g:o,b:e}=r(t),s=r=>Math.round(r*(1-a));return`#${[s(n),s(o),s(e)].map((r=>r.toString(16).padStart(2,"0"))).join("")}`},n=(t,a=.2)=>{const{r:n,g:o,b:e}=r(t);return`rgba(${n}, ${o}, ${e}, ${a})`};export{n as a,a as s,t};
